var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NPC_NULL","text":{"KOREA":"크윽…!","JPN":"ううっ……！","ENG":"Kgh...!","TWN":"呃……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"휴… 깨어나서 다행이야. 아까는 진짜 죽어버린 줄 알았지 뭐야.","JPN":"ふぅ……目が覚めてよかったよ。さっきは本当に死んだのかと思った。","ENG":"Phew... Thank goodness you woke up. I thought you really died just then.","TWN":"呼……醒過來真是太好了。剛才還以為你真死了呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L6_1","type":"dialog","speaker":"MAVKA_DOLL_NPC_NULL","text":{"KOREA":"……이제 날 어쩔 생각이야?","JPN":"……これから私をどうするつもりだ？","ENG":"...So, what are you going to do with me?","TWN":"……你現在打算怎麼處置我？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"얘가 오해할 소릴 한다. 난 네 적이 아니라니까?","JPN":"人聞きの悪いこと言わないで。私はあなたの敵じゃないよ？","ENG":"Not this again. I told you, I’m not your enemy.","TWN":"又說這種讓人誤會的話……我不是你的敵人……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"여기 고물더미를 뒤지다가 우연히 널 발견한 것뿐인걸.","JPN":"ここの古鉄を漁ってたら偶然あなたを見つけたの。","ENG":"I just found you while rummaging through the junk pile.","TWN":"我只是偶然在這堆廢鐵裡發現了你。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"너한테 해를 끼칠 생각은 전혀 없으니까 안심해줘.","JPN":"あなたに危害を加えるつもりはまったくないから、安心して。","ENG":"Don't worry. I have no intention of harming you.","TWN":"我完全沒有想要傷害你的意思，請放心。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"휴… 조금은 진정된 것 같아 다행이야.","JPN":"はぁ……ちょっとは落ち着いたみたいでよかった。","ENG":"Phew... I'm glad you calmed down a little.","TWN":"呼……看起來稍微冷靜點了，真是太好了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NPC_NULL","text":{"KOREA":"너 코피가….","JPN":"あなた、鼻から血が……","ENG":"You have a nosebleed...","TWN":"你流鼻血了……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"코피? 아야얏…!","JPN":"鼻血？　わっ……！","ENG":"Nosebleed? Oww...!","TWN":"鼻血？哎呀呀……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아파라… 아까 너랑 부딪혀서 그랬나봐.","JPN":"痛……さっきあなたとぶつかったせいかも。","ENG":"Ouch... I think it's from bumping into you.","TWN":"好痛……剛才是不是撞到你了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아야야… 다음부턴 조심해야지.","JPN":"うう……次からは気をつけないとね。","ENG":"Oww... I'll be careful next time.","TWN":"哎呀呀……下次一定要小心點。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그래도 이 정도는 괜찮아. 이래뵈도 난 카운터니까 튼튼하거든.","JPN":"でもこれぐらいは平気だよ。こう見えても私、カウンタ―だから丈夫なんだ。","ENG":"But I'm all right. I'm strong because I'm a Counter.","TWN":"不過我不要緊啦，畢竟我是制裁者，很強壯的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NPC_NULL","text":{"KOREA":"넌 정말 <color=#ffd34c>북방군</color>이 아닌거야?","JPN":"あなたは本当に<color=#ffd34c>北方軍</color>じゃないの？","ENG":"You're really not from the <color=#ffd34c>Northern Army</color>?","TWN":"你真的不是<color=#ffd34c>北方軍</color>的人嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아니래두. 내가 나쁜 사람이었다면, 움직이지도 못할 너를 내버려둘 리가 없잖아?","JPN":"だから違うって。本当に私が悪い人なら、動けないあなたを見て何もしないわけがないでしょう？","ENG":"No. If I was a bad person, I wouldn't let you be free when you can't even move, right?","TWN":"不是啦。如果我是壞人，怎麼可能放過你這個動都動不了的人呢？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아참, 내 이름은 사샤. 사샤 가가리나야.","JPN":"自己紹介がまだだったね。私はサシャ。サシャ・ガガリナって言うの。","ENG":"Oh, right. I'm Sasha. Sasha Gagarina.","TWN":"對了，我的名字是莎夏。莎夏·加格林娜。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"히힛. 성은 내가 멋대로 지은거지만.","JPN":"苗字は自分で適当につけたんだけどね。えへっ。","ENG":"Hehe. But I gave myself my last name.","TWN":"嘿嘿。姓是我自己隨便取的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"너는?","JPN":"あなたは？","ENG":"What about you?","TWN":"你是誰？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……마브카.","JPN":"……マブカ。","ENG":"...Mavka.","TWN":"……瑪卡。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>…….</color>","JPN":"<color=#ffd34c>……</color>","ENG":"<color=#ffd34c>...</color>","TWN":"<color=#ffd34c>……</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"오~ 이쁜 이름이네. 책에서 몇 번 읽은 적 있어.","JPN":"へえ～いい名前だね。何度か本で読んだことある。","ENG":"Ooh... That's a pretty name. I've seen it in a book before.","TWN":"喔——！喔喔。好美的名字。我在書裡讀過幾次。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"숲 속에 사는 요정의 이름이랬나? 엄청 이쁜 모습이라던데 정말 그렇네.","JPN":"森の妖精の名前なんだっけ？　すごく綺麗な妖精だって書かれてたけど、本当なんだね。","ENG":"It's the name of the fairy that lives in the forest, right? She was really pretty, and so are you.","TWN":"那是住在森林裡的妖精的名字吧？據說非常漂亮，果然如此呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아하하… 혹시 내가 말 실수라도 한 걸까?","JPN":"あはは……私今、なにか変なこと言った？","ENG":"Ah hah hah... Did I say something wrong?","TWN":"哈哈哈……我是不是說錯話了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"딱히, 그냥 말이 많은 애라고 생각했을 뿐이야.","JPN":"別に。お喋りな子だと思っただけ。","ENG":"Not really. I was just thinking that you talk a lot.","TWN":"不是，我只是覺得你話很多而已。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그런가? 난 그냥 어색한 느낌이 싫었을 뿐인데.","JPN":"そうかな？　でもずっと無言でいるのも気まずいでしょ？","ENG":"You think so? I just hate feeling awkward, that's all.","TWN":"是嗎？我只是怕尷尬而已……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아차차, 이러고 있을 때가 아니지. 빨리 네 몸을 고쳐줘야겠다.","JPN":"あっ、こうしてる場合じゃなかった。あなたの体を直してあげないと。","ENG":"Oops. What am I doing? I should fix you up.","TWN":"哎呀呀，現在不是說這個時候。得趕緊修好你的身體。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"고친다고? 그게 가능한 거야?","JPN":"直す？　そんなことできるの？","ENG":"Fix me? Is that possible?","TWN":"修好？這可能嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응. 난 카운터거든. 물건을 고치는게 특기지.","JPN":"うん。私はカウンタ―だからね。物を直すのが得意なんだ。","ENG":"Yup. I'm a Counter, and my specialty is fixing stuff.","TWN":"嗯。我是制裁者，修東西是我的專長。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"원래 복잡한 구조는 힘든데 네가 눈을 떴다는 건, 내 능력이 통했다는 거잖아?","JPN":"構造が複雑だと難しいんだけど、あなたがちゃんと目を覚ましたってことは私の能力が効いたってことでしょう？","ENG":"Complex structures are hard to do, but seeing how you woke up, my abilities worked, right?","TWN":"本來是結構越複雜就越難修好，不過你能睜開眼睛，說明我的能力起作用了，對吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"일단 움직일 수 있게 한번 손을 봐줄게?","JPN":"動けるように、ちょっとやってみるね。","ENG":"First, let me see your hand so I can fix it.","TWN":"我先幫你修一下，讓你起碼能先動起來？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"자…… 그럼!","JPN":"さて……と！","ENG":"Okay... Then!","TWN":"那麼……開始吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"뭐, 뭐하는거야?!","JPN":"な、何するの！？","ENG":"W-what are you doing?!","TWN":"你，你在做什麼？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"수리중이야. 난 이런식으로 고치거든.","JPN":"何って、修理だよ。私のやり方。","ENG":"I'm fixing you. This is how I do it.","TWN":"在修理呢。我就是這樣修東西的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"혹시 아프진 않았니?","JPN":"痛くなかった？","ENG":"Does it hurt?","TWN":"你不覺得痛吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……별로.","JPN":"……うん。","ENG":"...No.","TWN":"……不會。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"설마 그렇게 한다고 고쳐질 리가…!","JPN":"こんなやり方で、そんな簡単に直るわけが……！","ENG":"But doing that won't fix–!","TWN":"不，不對……怎麼可能就這樣修好……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"어라? 어떻게…","JPN":"あれ？　なんで……","ENG":"Huh? How...?","TWN":"什麼？怎麼會……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이런 방법으로… 진짜 고쳐졌다고?","JPN":"こんなやり方で……本当に直った？","ENG":"You really fixed it... doing that?","TWN":"用這種方法……真的修好了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"오호? 설마 진짜로 고쳐질 줄은 몰랐는데.","JPN":"おおっ！　まさか本当にできちゃうとは思わなかったよ。","ENG":"Oh? I didn't think it would work either.","TWN":"喔？我也沒想到真能成功呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"거봐! 역시 이 방법을 쓰니까 한방에 해결….","JPN":"ほら！　やっぱりこの方法だと一発で解決……","ENG":"See! I knew this would fix you up–","TWN":"看吧！按照我的方法一下子就解決了……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"으악!","JPN":"うわっ！","ENG":"Whoa!","TWN":"呃啊！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"고쳐줘서 고마워. 하지만 난 네 곁에 있을 수 없어.","JPN":"直してくれてありがとう。でも私はあなたと一緒にはいられない。","ENG":"Thanks for fixing me. But I can't stay.","TWN":"謝謝你修好我。但我不能留在你身邊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"난 아직 전투중이야. 언제 그 녀석이 다시 올지 몰라.","JPN":"私はまだ戦闘中だから。いつあいつが戻って来るかわからないもの。","ENG":"I'm still in a battle. I don't know when she'll come back for me again.","TWN":"我還在戰鬥中。那傢伙不知道什麼時候會再來。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그, 그 녀석이라니?!","JPN":"あ、あいつって！？","ENG":"W-who are you talking about?!","TWN":"那，那傢伙？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그럼, 바로 떠나려고?","JPN":"じゃあ、行っちゃうの？","ENG":"Then, you're going to leave right now?","TWN":"所以，你要離開了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……널 위해서야. 나랑 가까이 있으면 좋지 않아.","JPN":"……あなたのためだ。私と一緒にいると危ない。","ENG":"...It's for your own good. Nothing good comes from being near me.","TWN":"……這也是為了你好，和我在一起對你沒有好處。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"저, 정말로 괜찮겠어?! 너 갈 곳도 없는 것 같은데….","JPN":"でも本当に大丈夫！？　あなた、行く当てもないんじゃないの……？","ENG":"A-are you sure you'll be okay? But you have nowhere to go...","TWN":"真，真的沒問題嗎？！你好像也沒有地方可去……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"차라리 우리 마을에 와서 지내는 게 어때?","JPN":"うちの村に来るのはどう？","ENG":"How about staying with me in the village?","TWN":"不如來我們村子住怎麼樣？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"방금 내가 한 말, 뭘로 들은 거야?","JPN":"今の話、聞いてた？","ENG":"Didn't you hear what I just said?","TWN":"剛才我說的話，你沒聽明白嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그, 그치만 내 능력이 풀리기라도 하면 또 고물더미에 박히게 될 거야!","JPN":"で、でももし私の能力の効果が切れたりでもしたら、また古鉄の山に捨てられちゃうよ！","ENG":"B-but if my ability wears off, you'll end up in the junk pile again!","TWN":"但，但如果我的能力失效了，你又會變成一堆廢鐵了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"미안해. 역시 난 떠나야겠어. 그럼…!","JPN":"ごめんなさい。やっぱり私は行かないと。じゃあ……！","ENG":"I'm sorry. But I have to go. Then...!","TWN":"對不起，我還是得走。就這樣……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L23_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"엇, 잠깐…?","JPN":"……っ！？","ENG":"Huh? What...?","TWN":"呃？怎麼……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_11"},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"괘, 괜찮아 마브카?","JPN":"ま、マブカ！　大丈夫？","ENG":"A-are you all right, Mavka?","TWN":"你，你沒事吧，瑪卡？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"너… 무슨 짓을 한 거야.","JPN":"あなた……私に何をしたの。","ENG":"What... did you to do me?","TWN":"你……對我做了什麼。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아까 말했잖아. 능력이 풀릴 수도 있다고.","JPN":"さっき言ったでしょう。能力の効果が切れるかもしれないって。","ENG":"See? I told you. My ability might wear off.","TWN":"剛才不是說了？我的能力會失效的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"역시 이상할 정도로 일이 잘 풀리면 꼭 이렇다니까.","JPN":"やっぱり……上手くいきすぎてると思ったんだよ。","ENG":"It always does when everything seems to go smoothly.","TWN":"尤其是事情順利得不可思議的時候……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};